final:
module left_shift(
    input [3:0] data_in,
    input shift,
    output reg [3:0] data_out
);
  wire [3:0] _tap_data_in = data_in & {4{1'b1}};


always @(*) begin
    if (shift) begin
        data_out = {data_in[2:0], 1'b0};
    end
    else begin
        data_out = data_in;
    end
end

endmodule
